  ('dietitian-moex-08874', 'dietitian', 'dietitian-moex-098-da9d23a3', 'sub-dietitian-06', NULL, 'single_choice', '有關有害金屬中毒之敘述，下列何者錯誤？', '["有機汞會引起水俁病，影響中樞神經", "錳會妨礙血色素之合成，引起貧血", "金屬侵入生物體，以經呼吸道為主", "攝取微量時便顯現有害症狀之金屬可定義為有害金屬"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:51+00:00", "source_pdf_sha1": "e8ef415595ad", "answer_pdf_sha1": "d0184ce20793", "source_family": "moex-gov-tw", "moex": {"exam_code": "098140", "c": "113", "s": "6001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "食品衛生與安全", "year": "098", "exam_name": "098年第二次醫事人員、中醫師、心理師、營養師、醫師分試 、法醫師", "original_question_number": 9, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
